using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented = true
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized: {deserialized}");
Console.WriteLine();

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
//    Use a source-gen-only context so only Widget is resolvable.
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = WidgetContext.Default
};

if (limitedOptions.TryGetTypeInfo(typeof(Widget), out JsonTypeInfo? widgetInfo))
    Console.WriteLine($"Widget metadata available — type: {widgetInfo!.Type.Name}");
else
    Console.WriteLine("Widget metadata NOT available");

if (limitedOptions.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("Person metadata available");
else
    Console.WriteLine("Person metadata NOT available (expected — not in this context)");

// Types used in the demo
public record Person(string Name, int Age);
public record Widget(string Id, double Weight);

// Source-generated context that only knows about Widget
[JsonSerializable(typeof(Widget))]
public partial class WidgetContext : JsonSerializerContext;

